function candidate(references) {
  while (references.length > 1) {
    const reference = references.pop();
    let owner;
    let property;

    if (Array.isArray(reference)) {
      owner = reference[0];
      property = reference[1];
    } else {
      owner = reference.owner ?? reference.object ?? reference.target;
      property = reference.key ?? reference.property ?? reference.name;
    }

    const value = owner[property];
    if (Array.isArray(value)) {
      owner[property] = value.filter((entry) => entry !== undefined);
    }
  }
}
